"use client";

import { Mail } from "lucide-react";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";

export default function ForgotPasswordPage() {
  const router = useRouter();

  const [email, setEmail] = useState("");
  const [message, setMessage] = useState(null);
  const [isLoading, setIsLoading] = useState(false);

  // 🔐 Block logged in users
  useEffect(() => {
    const token = localStorage.getItem("accessToken");
    if (token) {
      router.replace("/");
    }
  }, []);

  const handleSendOtp = async (e) => {
    e.preventDefault();

    if (!email) {
      setMessage({ type: "error", text: "Please enter your email" });
      return;
    }

    try {
      setIsLoading(true);
      setMessage(null);

      const res = await fetch("http://localhost:5000/user/forgotPassword", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email }),
      });

      const data = await res.json();

      if (!res.ok) throw new Error(data.message);

      router.push(`/reset-password?email=${email}`);
    } catch (err) {
      setMessage({
        type: "error",
        text: err.message || "Failed to send OTP",
      });
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex justify-center items-center bg-gray-50">
      <div className="bg-white p-10 rounded-2xl shadow-xl w-[420px]">
        <h1 className="text-2xl font-semibold mb-2 text-center">
          Forgot Password
        </h1>

        <p className="text-sm text-gray-600 mb-5 text-center">
          Enter your email to receive OTP
        </p>

        <form onSubmit={handleSendOtp} className="space-y-4">
          <div className="relative">
            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="email"
              placeholder="Enter your email"
              className="pl-10 h-11 border rounded-lg w-full"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
            />
          </div>

          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-blue-500 h-11 text-white rounded-lg hover:bg-blue-600 disabled:opacity-60"
          >
            {isLoading ? "Sending..." : "Send OTP"}
          </button>
        </form>

        {message && (
          <p
            className={`mt-4 text-sm text-center ${
              message.type === "error" ? "text-red-500" : "text-green-600"
            }`}
          >
            {message.text}
          </p>
        )}
      </div>
    </div>
  );
}
